        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().then(() => setIsFullscreen(true)).catch(err => console.error(err));
        } else {
            if (document.exitFullscreen) {
                document.exitFullscreen().then(() => setIsFullscreen(false)).catch(err => console.error(err));
            }
        }
    };

    // Permission check memoized for children
    const hasPermission = useCallback((permName: string) => {
        if (props.currentUserRole === 'ADMIN') return true;
        const roleObj = props.roles.find(r => r.name === props.currentUserRole);
        if (!roleObj) return false;
        return roleObj.permissions ? roleObj.permissions.includes(permName) : false;
    }, [props.roles, props.currentUserRole]);

    // Name resolution memoized for performance
    const resolveName = useCallback((username?: string | null) => {
        if (!username) return '-';
        const u = props.users.find(x => x.username === username);
        return (u?.nickname || username).toUpperCase();
    }, [props.users]);

    const resetEntry = () => {
        setSelectedPart(null);
        setSelectedWorkplace(null);
        setQuantity('');
        setQuantityUnit(mode === 'logistics' ? 'pallet' : 'pcs');
        setPriority('NORMAL');
        setLogisticsRef('');
        setLogisticsPlate('');
        setLogisticsOp('');
        setSourceSector(null);
        setTargetSector(null);
    };

    const handleAddTask = async () => {
        if (mode === 'production') {
            if (!selectedPart || !selectedWorkplace || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                selectedPart,
                selectedWorkplace,
                quantity,
                quantityUnit,
                priority,
                false,
                '',
                true
            );
            resetEntry();
        } else {
            if (!logisticsRef || !logisticsOp || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                logisticsRef,
                logisticsOp,
                quantity,
                quantityUnit,
                priority,
                true,
                logisticsPlate,
                false,
                sourceSector,
                targetSector
            );
            resetEntry();
        }
    };

    const counts = useMemo(() => ({
        tasks: props.tasks.filter(t => !t.isDone).length,
        pendingRequests: props.partRequests.length + props.bomRequests.length,
        erpBlockages: (props.erpBlockages || []).filter(b => b.status !== 'ready').length
    }), [props.tasks, props.partRequests, props.bomRequests, props.erpBlockages]);

    return (
        <div className="flex flex-col h-screen overflow-hidden bg-gray-900">
            {/* Top UI Bar */}
            <AppHeader 
                currentUser={props.currentUser}
                currentUserRole={props.currentUserRole}
                users={props.users}
                onLogout={props.onLogout}
                language={language as any}
                setLanguage={setLanguage as any}
                t={t}
                isFullscreen={isFullscreen}
                onToggleFullscreen={toggleFullscreen}
                installPrompt={props.installPrompt}
                onInstallApp={props.onInstallApp}
                hasPermission={hasPermission}
                resolveName={resolveName}
                isBreakActive={props.isBreakActive}
            />

            {/* Application Tab Selector */}
            <TabNavigator 
                activeTab={activeTab}
                setActiveTab={setActiveTab}
                hasPermission={hasPermission}
                t={t}
                counts={counts}
                currentUserRole={props.currentUserRole}
                systemConfig={props.systemConfig}
            />

            {/* Main Application Container */}
            <main className="flex-grow overflow-y-auto custom-scrollbar p-4 sm:p-6">
                <div className="max-w-7xl mx-auto h-full">
                    {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                        <ProductionEntry 
                            mode={mode}
                            setMode={setMode}
                            selectedPart={selectedPart}
                            setSelectedPart={setSelectedPart}
                            selectedWorkplace={selectedWorkplace}
                            setSelectedWorkplace={setSelectedWorkplace}
                            logisticsRef={logisticsRef}
                            setLogisticsRef={setLogisticsRef}
                            logisticsPlate={logisticsPlate}
                            setLogisticsPlate={setLogisticsPlate}
                            logisticsOp={logisticsOp}
                            setLogisticsOp={setLogisticsOp}
                            sourceSector={sourceSector}
                            setSourceSector={setSourceSector}
                            targetSector={targetSector}
                            setTargetSector={setTargetSector}
                            quantity={quantity}
                            setQuantity={setQuantity}
                            quantityUnit={quantityUnit}
                            setQuantityUnit={setQuantityUnit}
                            priority={priority}
                            setPriority={setPriority}
                            parts={props.parts}
                            workplaces={props.workplaces}
                            logisticsOperationsList={props.logisticsOperations}
                            mapSectors={props.mapSectors}
                            t={t}
                            language={language}
                            hasPermission={hasPermission}
                            handleAdd={handleAddTask}
                            onRequestPart={props.onRequestPart}
                        />
                    )}

                    {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                        <TaskList 
                            currentUser={props.currentUserRole as any}
                            currentUserName={props.currentUser}
                            tasks={props.tasks}
                            missingReasons={props.missingReasons}
                            mapSectors={props.mapSectors}
                            onToggleTask={props.onToggleTask}
                            onEditTask={props.onUpdateTask}
                            onDeleteTask={props.onDeleteTask}
                            onToggleMissing={props.onToggleMissing}
                            onSetInProgress={props.onSetInProgress}
                            onToggleBlock={props.onToggleBlock}
                            onToggleManualBlock={props.onToggleManualBlock}
                            onExhaustSearch={props.onExhaustSearch}
                            onMarkAsIncorrect={props.onMarkAsIncorrect}
                            onAddNote={props.onAddNote}
                            onReleaseTask={props.onReleaseTask}
                            onAuditPart={props.onStartAudit}
                            onFinishAudit={props.onFinishAudit}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'quick_action' && hasPermission('perm_tab_quick_action') && (
                        <QuickActionTab />
                    )}

                    {activeTab === 'bom' && hasPermission('perm_tab_bom') && (
                        <BOMScreen 
                            parts={props.parts}
                            workplaces={props.workplaces}
                            bomMap={props.bomMap}
                            onAddTask={props.onAddTask}
                            onRequestBOM={props.onRequestBOM}
                            t={t}
                            language={language}
                        />
                    )}

                    {activeTab === 'catalog' && hasPermission('perm_tab_catalog') && (
                        <PartCatalogTab 
                            parts={props.parts}
                            onSelectPart={(p) => { setSelectedPart(p.value); setActiveTab('entry'); }}
                        />
                    )}

                    {activeTab === 'missing' && hasPermission('perm_tab_missing') && (
                        <MissingItemsTab 
                            tasks={props.tasks}
                            onDeleteMissingItem={props.onDeleteMissingItem}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && (
                        <InventoryTab 
                            currentUser={props.currentUser}
                            tasks={props.tasks}
                            onAddTask={props.onAddTask}
                            onUpdateTask={props.onUpdateTask}
                            onToggleTask={props.onToggleTask}
                            onDeleteTask={props.onDeleteTask}
                            hasPermission={hasPermission}
                            parts={props.parts.map(p => p.value)}
                            onRequestPart={props.onRequestPart}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && (
                        <LogisticsCenterTab 
                            tasks={props.tasks} 
                            draftTasks={props.draftTasks}
                            users={props.users}
                            fetchSanons={props.fetchSanons}
                            onDeleteTask={props.onDeleteTask} 
                            hasPermission={hasPermission} 
                            resolveName={resolveName} 
                        />
                    )}

                    {activeTab === 'scrap_weighing' && hasPermission('perm_scrap_add') && (
                        <ScrapWeighingTab 
                            currentUser={props.currentUser}
                            bins={props.scrapBins}
                            metals={props.scrapMetals}
                            prices={props.scrapPrices}
                            actualScrap={props.actualScrap}
                            scrapSanons={props.scrapSanons}
                            onAddRecord={props.onAddScrapRecord}
                            onBulkAddScrapRecords={props.onBulkAddScrapRecords}
                            onDeleteRecord={props.onDeleteScrapRecord}
                            onFinalizeArchive={props.onFinalizeScrapArchive}
                            onAddTask={props.onAddTask}
                            onUpdateTask={props.onUpdateTask}
                            onDeleteTask={props.onDeleteTask}
                            tasks={props.tasks}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'scrap_warehouse' && hasPermission('perm_scrap_list') && (
                        <ScrapWarehouseTab 
                            currentUser={props.currentUser}
                            actualScrap={props.actualScrap}
                            bins={props.scrapBins}
                            metals={props.scrapMetals}
                            prices={props.scrapPrices}
                            onDeleteRecord={props.onDeleteScrapRecord}
                            onUpdateRecord={props.onUpdateScrapRecord}
                            onExpedite={props.onExpediteScrap}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'scrap_archive' && hasPermission('perm_scrap_archive') && (
                        <ScrapArchiveTab 
                            scrapArchives={props.scrapSanons}
                            bins={props.scrapBins}
                            metals={props.scrapMetals}
                            prices={props.scrapPrices}
                            onUpdateArchivedItem={props.onUpdateArchivedScrapItem}
                            onUpdateScrapArchive={props.onUpdateScrapArchive}
                            onDeleteArchivedItem={props.onDeleteArchivedScrapItem}
                            onDeleteArchive={props.onDeleteScrapArchive}
                            onFetchArchives={props.onFetchScrapArchives}
                            resolveName={resolveName}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'scrap_analytics' && hasPermission('perm_tab_scrap_analytics') && (
                        <ScrapAnalyticsTab 
                            scrapSanons={props.scrapSanons}
                            scrapPrices={props.scrapPrices}
                            scrapMetals={props.scrapMetals}
                            onFetchArchives={props.onFetchScrapArchives}
                        />
                    )}

                    {activeTab === 'map' && hasPermission('perm_tab_map') && (
                        <MapVisualizationTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            workplaces={props.workplaces}
                            logisticsOperations={props.logisticsOperations}
                            mapObstacles={props.mapObstacles}
                            systemConfig={props.systemConfig}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logs' && hasPermission('perm_tab_logs') && (
                        <TransactionLogTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'erp' && hasPermission('perm_tab_erp') && (
                        <ERPBlockageTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            parts={props.parts}
                            blockages={props.erpBlockages}
                            resolveName={resolveName}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && (
                        <AnalyticsTab 
                            systemConfig={props.systemConfig}
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'settings' && hasPermission('perm_tab_settings') && (
                        <SettingsTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            installPrompt={props.installPrompt}
                            onInstallApp={props.onInstallApp}
                            systemConfig={props.systemConfig}
                            onUpdateSystemConfig={props.onUpdateSystemConfig}
                            onUpdateAdminKey={props.onUpdateAdminKey}
                            onToggleAdminLock={props.onToggleAdminLock}
                        />
                    )}

                    {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && (
                        <PermissionsTab 
                            roles={props.roles}
                            onAddRole={props.onAddRole}
                            onDeleteRole={props.onDeleteRole}
                            onUpdatePermission={props.onUpdatePermission}
                            onVerifyAdminPassword={props.onVerifyAdminPassword}
                        />
                    )}
                </div>
            </main>
        </div>
    );
};

export default PartSearchScreen;

import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  setDoc,
  getDoc,
  arrayUnion,
  writeBatch,
  getDocs
} from 'firebase/firestore';
import { DBItem, MapSector, PartRequest, BOMRequest, BOMComponent, MapObstacle, CSItem, QuickActionConfig } from '../../types/appTypes';

export const useMasterData = () => {
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, BOMComponent[]>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]);
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [mapObstacles, setMapObstacles] = useState<MapObstacle[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [quickActions, setQuickActions] = useState<QuickActionConfig[]>([]);

  const [customers, setCustomers] = useState<CSItem[]>([]);
  const [suppliers, setSuppliers] = useState<CSItem[]>([]);

  useEffect(() => {
    const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
    const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
        const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
        setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
    });
    const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
    const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));

    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (docSnap) => {
        const cleanMap: Record<string, string> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.value) cleanMap[item.value] = item.description || '';
                });
            }
        }
        setPartsMap(cleanMap);
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (docSnap) => {
        const cleanMap: Record<string, BOMComponent[]> = {};
        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.items && Array.isArray(data.items)) {
                data.items.forEach((item: any) => {
                    if (item.parent && item.child) {
                        if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                        cleanMap[item.parent].push({ child: item.child, consumption: item.consumption || 0 });
                    }
                });
            }
        }
        setBomMap(cleanMap);
    });

    const unsubQuickActions = onSnapshot(doc(db, 'settings', 'quick_actions'), (s) => {
        setQuickActions(s.exists() ? (s.data().items || []) : []);
    });

    const unsubObstacles = onSnapshot(doc(db, 'settings', 'map_layout'), (docSnap) => {
        if (docSnap.exists()) {
            setMapObstacles(docSnap.data().obstacles || []);
        } else {
            setMapObstacles([]);
        }
    });

    const unsubCustomers = onSnapshot(doc(db, 'CSDB', 'customers'), (s) => {
        setCustomers(s.exists() ? (s.data().items || []) : []);
    });
    const unsubSuppliers = onSnapshot(doc(db, 'CSDB', 'suppliers'), (s) => {
        setSuppliers(s.exists() ? (s.data().items || []) : []);
    });

    return () => { 
        unsubWp(); unsubLogOps(); unsubSectors(); unsubPartReq(); unsubBomReq();
        unsubParts(); unsubBOM(); unsubObstacles();
        unsubCustomers(); unsubSuppliers(); unsubQuickActions();
    };
  }, []);

  const onAddQuickAction = async (config: Omit<QuickActionConfig, 'id'>) => {
      const newAction = { ...config, id: crypto.randomUUID() };
      await setDoc(doc(db, 'settings', 'quick_actions'), { items: arrayUnion(newAction) }, { merge: true });
  };

  const onDeleteQuickAction = async (id: string) => {
      const ref = doc(db, 'settings', 'quick_actions');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const filtered = (snap.data().items || []).filter((i: any) => i.id !== id);
          await updateDoc(ref, { items: filtered });
      }
  };

  // CSDB Actions
  const onAddCSItem = async (category: 'customers' | 'suppliers', name: string, description: string = '') => {
      try {
          const newItem: CSItem = { id: crypto.randomUUID(), name: name.toUpperCase(), description };
          await setDoc(doc(db, 'CSDB', category), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };

  const onBatchAddCSItems = async (category: 'customers' | 'suppliers', lines: string[]) => {
      try {
          const itemsToAdd = lines.map(line => {
              if (!line.trim()) return null;
              const [n, d] = line.split(';');
              return { id: crypto.randomUUID(), name: n.trim().toUpperCase(), description: d ? d.trim() : '' };
          }).filter(Boolean);
          if (itemsToAdd.length > 0) {
              await setDoc(doc(db, 'CSDB', category), { items: arrayUnion(...itemsToAdd) }, { merge: true });
          }
      } catch (e) { console.error(e); }
  };

  const onDeleteCSItem = async (category: 'customers' | 'suppliers', id: string) => {
      try {
          const ref = doc(db, 'CSDB', category);
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const current = snap.data().items || [];
              const filtered = current.filter((i: any) => i.id !== id);
              await updateDoc(ref, { items: filtered });
          }
      } catch (e) { console.error(e); }
  };

  const onDeleteAllCSItems = async (category: 'customers' | 'suppliers') => {
      try { await setDoc(doc(db, 'CSDB', category), { items: [] }); } catch (e) { console.error(e); }
  };

  // Obstacles
  const onAddMapObstacle = async (obs: Omit<MapObstacle, 'id'>) => {
      const id = `obs_${Date.now()}`;
      await setDoc(doc(db, 'settings', 'map_layout'), { 
          obstacles: arrayUnion({ ...obs, id }) 
      }, { merge: true });
  };
  const onDeleteMapObstacle = async (id: string) => {
      const ref = doc(db, 'settings', 'map_layout');
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const filtered = (snap.data().obstacles || []).filter((o: any) => o.id !== id);
          await updateDoc(ref, { obstacles: filtered });
      }
  };

  // Workplaces
  const onAddWorkplace = async (val: string, time: number = 0, x: number = 0, y: number = 0) => {
      await addDoc(collection(db, 'workplaces'), { value: val, standardTime: time, coordX: x, coordY: y });
  };
  const onUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => {
      await updateDoc(doc(db, 'workplaces', id), updates);
  };
  const onDeleteWorkplace = async (id: string) => {
      await deleteDoc(doc(db, 'workplaces', id));
  };
  const onDeleteAllWorkplaces = async () => {
      const snap = await getDocs(collection(db, 'workplaces'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };
  const onBatchAddWorkplaces = async (vals: string[]) => {
      const batch = writeBatch(db);
      vals.forEach(line => {
          if (!line.trim()) return;
          const [val, time] = line.split(';');
          const ref = doc(collection(db, 'workplaces'));
          batch.set(ref, { value: val.trim(), standardTime: parseInt(time) || 0 });
      });
      await batch.commit();
  };

  // Logistics Operations
  const onAddLogisticsOperation = async (val: string, time: number = 0, dist: number = 0, x: number = 0, y: number = 0, defaultSource?: string | null, defaultTarget?: string | null) => { 
      await addDoc(collection(db, 'logistics_operations'), { 
          value: val, 
          standardTime: time, 
          distancePx: dist, 
          coordX: x, 
          coordY: y,
          defaultSourceSectorId: defaultSource || null,
          defaultTargetSectorId: defaultTarget || null
      }); 
  };
  const onUpdateLogisticsOperation = async (id: string, updates: Partial<DBItem>) => { 
      await updateDoc(doc(db, 'logistics_operations', id), updates); 
  };
  const onDeleteLogisticsOperation = async (id: string) => { await deleteDoc(doc(db, 'logistics_operations', id)); };
  const onDeleteAllLogisticsOperations = async () => {
      const snap = await getDocs(collection(db, 'logistics_operations'));
      const batch = writeBatch(db);
      snap.forEach(d => batch.delete(d.ref));
      await batch.commit();
  };

  // Map Sectors
  const onAddMapSector = async (name: string, x: number, y: number, color?: string) => { await addDoc(collection(db, 'map_sectors'), { name, coordX: x, coordY: y, color }); };
  const onUpdateMapSector = async (id: string, updates: Partial<MapSector>) => { await updateDoc(doc(db, 'map_sectors', id), updates); };
  const onDeleteMapSector = async (id: string) => { await deleteDoc(doc(db, 'map_sectors', id)); };

  // Parts (Single Doc Pattern)
  const onAddPart = async (value: string, description: string = '') => {
      try {
          const newItem = { 
            value: value.toUpperCase(), 
            description 
          };
          await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddParts = async (vals: string[]) => {
    try {
      const itemsToAdd: any[] = [];
      vals.forEach((valLine) => {
        if (!valLine.trim()) return;
        const [p, d] = valLine.split(';');
        if(p) { 
          itemsToAdd.push({ 
            value: p.trim().toUpperCase(), 
            description: d ? d.trim() : '' 
          }); 
        }
      });
      if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'parts'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
    } catch (error) { console.error("Error batch adding parts:", error); throw error; }
  };
  const onDeletePart = async (val: string) => {
      try {
          const ref = doc(db, 'settings', 'parts');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => i.value !== val);
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error("Error deleting part:", e); }
  };
  const onDeleteAllParts = async () => { try { await setDoc(doc(db, 'settings', 'parts'), { items: [] }); } catch (e) { console.error("Error clearing parts:", e); } };

  // BOM (Single Doc Pattern - Optimized for Quota Guard)
  const onAddBOMItem = async (parent: string, child: string, qty: number) => {
      try {
          const newItem = { 
              parent: parent.toUpperCase(), 
              child: child.toUpperCase(), 
              consumption: qty 
          };
          await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(newItem) }, { merge: true });
      } catch (e) { console.error(e); }
  };
  const onBatchAddBOMItems = async (vals: string[]) => {
      try {
          const itemsToAdd: any[] = [];
          vals.forEach(line => {
              if (!line.trim()) return;
              const [p, c, q] = line.split(';');
              if (p && c) { 
                  itemsToAdd.push({ 
                      parent: p.trim().toUpperCase(), 
                      child: c.trim().toUpperCase(), 
                      consumption: parseFloat(q?.replace(',', '.') || '0') 
                  }); 
              }
          });
          if (itemsToAdd.length > 0) { await setDoc(doc(db, 'settings', 'bom'), { items: arrayUnion(...itemsToAdd) }, { merge: true }); }
      } catch (e) { console.error(e); }
  };
  const onDeleteBOMItem = async (parent: string, child: string) => {
      try {
          const ref = doc(db, 'settings', 'bom');
          const snap = await getDoc(ref);
          if (snap.exists()) {
              const currentItems = snap.data().items || [];
              const newItems = currentItems.filter((i: any) => !(i.parent === parent && i.child === child));
              await updateDoc(ref, { items: newItems });
          }
      } catch (e) { console.error(e); }
  };
  const onDeleteAllBOMItems = async () => { try { await setDoc(doc(db, 'settings', 'bom'), { items: [] }); } catch (e) { console.error("Error clearing BOM:", e); } };

  // Requests
  const onRequestPart = async (part: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'part_requests'), { partNumber: part, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeletePartRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'part_requests', id)); } catch(e) { console.error(e); }
  };

  const onRequestBOM = async (parent: string) => {
    try {
        const user = localStorage.getItem('app_user') || 'Unknown';
        await addDoc(collection(db, 'bom_requests'), { parentPart: parent, requestedBy: user, requestedAt: Date.now() });
        return true;
    } catch (e) { return false; }
  };
  const onDeleteBOMRequest = async (id: string) => { 
      try { await deleteDoc(doc(db, 'bom_requests', id)); } catch(e) { console.error(e); }
  };

  return {
    partsMap, bomMap, workplaces, logisticsOperations, mapSectors, mapObstacles, partRequests, bomRequests,
    customers, suppliers, quickActions,
    onAddWorkplace, onUpdateWorkplace, onDeleteWorkplace, onDeleteAllWorkplaces, onBatchAddWorkplaces,
    onAddLogisticsOperation, onUpdateLogisticsOperation, onDeleteLogisticsOperation, onDeleteAllLogisticsOperations,
    onAddMapSector, onUpdateMapSector, onDeleteMapSector,
    onAddMapObstacle, onDeleteMapObstacle,
    onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts,
    onAddBOMItem, onBatchAddBOMItems, onDeleteBOMItem, onDeleteAllBOMItems,
    onAddCSItem, onBatchAddCSItems, onDeleteCSItem, onDeleteAllCSItems,
    onAddQuickAction, onDeleteQuickAction,
    onRequestPart, onDeletePartRequest, 
    onRequestBOM, onDeleteBOMRequest
  };
};

import React, { useState, useMemo, useEffect } from 'react';
import { Task, UserData, MapSector } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

declare var XLSX: any;

interface TransactionLogTabProps {
  tasks: Task[];
  draftTasks: Task[];
  fetchSanons: () => Promise<any[]>;
  users: UserData[];
  mapSectors: MapSector[];
  resolveName: (username?: string | null) => string;
}

const TransactionLogTab: React.FC<TransactionLogTabProps> = ({ 
  tasks, draftTasks, fetchSanons, users, mapSectors, resolveName 
}) => {
  const { t, language } = useLanguage();

  // Oprava 1: Predvolené časové okno na celý deň (00:00 - 23:59)
  const [dateFrom, setDateFrom] = useState(new Date().toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
  const [timeFrom, setTimeFrom] = useState('00:00');
  const [timeTo, setTimeTo] = useState('23:59');
  const [selectedUser, setSelectedUser] = useState<string>('');
  const [searchQuery, setSearchQuery] = useState('');

  const [historicalData, setHistoricalData] = useState<Task[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [loadedArchiveRange, setLoadedArchiveRange] = useState<string>('');

  // Načítanie histórie len ak je to potrebné
  useEffect(() => {
    const loadHistory = async () => {
      const today = new Date().toISOString().split('T')[0];
      // Ak pozeráme len dnešok, stačia nám live dáta a draft
      if (dateFrom === today && dateTo === today) return;

      // Ak už sme archív raz načítali, neťaháme ho znova (Quota Guard)
      if (historicalData.length > 0) return;

      setIsLoading(true);
      try {
        const sanons = await fetchSanons();
        const relevantTasks: Task[] = [];
        sanons.forEach(sanon => { 
            if (sanon.tasks && Array.isArray(sanon.tasks)) { 
                relevantTasks.push(...sanon.tasks); 
            } 
        });
        setHistoricalData(relevantTasks);
      } catch (e) { 
        console.error("Failed to load archive for logs", e); 
      } finally { 
        setIsLoading(false); 
      }
    };
    loadHistory();
  }, [dateFrom, dateTo, fetchSanons, historicalData.length]);

  const resolveSector = (sectorId?: string | null) => {
      if (!sectorId) return '';
      const s = mapSectors.find(x => x.id === sectorId);
      return s ? s.name : sectorId;
  };

  const filteredLogs = useMemo(() => {
    // Oprava 2: Robustné parsovanie dátumu v lokálnom čase
    const startTs = new Date(dateFrom + 'T00:00:00').getTime();
    const endTs = new Date(dateTo + 'T23:59:59').getTime();

    const allSource = [...tasks, ...draftTasks, ...historicalData];
    const unique = new Map();
    allSource.forEach(t => {
        if (t && t.id) unique.set(t.id, t);
    });
    const combined = Array.from(unique.values());

    return combined.filter(task => {
        // Logy zobrazujú len hotové veci
        if (!task.isDone) return false;

        const taskTime = task.completedAt || task.createdAt || 0;
        if (taskTime < startTs || taskTime > endTs) return false;

        // Kontrola časového okna (HH:mm)
        const dateObj = new Date(taskTime);
        const taskHHMM = dateObj.getHours().toString().padStart(2, '0') + ':' + 
                         dateObj.getMinutes().toString().padStart(2, '0');

        if (taskHHMM < timeFrom || taskHHMM > timeTo) return false;

        // Filter na užívateľa
        if (selectedUser && task.completedBy !== selectedUser && task.createdBy !== selectedUser) return false;

        // Fulltext search
        if (searchQuery) {
            const q = searchQuery.toLowerCase();
            const content = `${task.partNumber} ${task.workplace} ${task.note} ${resolveName(task.completedBy)}`.toLowerCase();
            if (!content.includes(q)) return false;
        }

        return true;
    }).sort((a,b) => (b.completedAt || b.createdAt || 0) - (a.completedAt || a.createdAt || 0));
  }, [tasks, draftTasks, historicalData, dateFrom, dateTo, timeFrom, timeTo, selectedUser, searchQuery, resolveName, mapSectors]);

  const getMovementInfo = (item: Task) => {
      let fromStr = '';
      let toStr = '';

      if (item.isLogistics) {
          const op = (item.workplace || '').toUpperCase();
          // Rozšírená heuristika pre Inbound/Outbound
          const isInbound = op.includes('VYKL') || op.includes('UNLOAD') || op.includes('PRÍJEM') || op.includes('INBOUND');
          const isOutbound = op.includes('NAKL') || op.includes('LOAD') || op.includes('EXPED') || op.includes('OUTBOUND');

          if (isInbound) {
              fromStr = item.note || item.plate || 'EXTERN';
              toStr = resolveSector(item.targetSectorId) || 'PRÍJEM';
          } else if (isOutbound) {
              fromStr = resolveSector(item.sourceSectorId) || 'SKLAD';
              toStr = item.note || item.plate || 'EXPEDÍCIA';
          } else {
              // Interný presun
              fromStr = resolveSector(item.sourceSectorId) || '?';
              toStr = resolveSector(item.targetSectorId) || '?';
          }
      } else {
          // Výroba
          fromStr = resolveSector(item.pickedFromSectorId) || 'SKLAD';
          toStr = item.workplace || 'VÝROBA';
      }

      return { fromStr, toStr };
  };

  const handleExport = () => {
      if (filteredLogs.length === 0) {
          alert(language === 'sk' ? 'Žiadne dáta na export.' : 'No data to export.');
          return;
      }
      const exportData = filteredLogs.map(t => {
          const { fromStr, toStr } = getMovementInfo(t);
          return {
              'Dátum': new Date(t.completedAt || t.createdAt || 0).toLocaleDateString('sk-SK'),
              'Čas': new Date(t.completedAt || t.createdAt || 0).toLocaleTimeString('sk-SK'),
              'Operátor': resolveName(t.completedBy || t.createdBy),
              'Diel / Ref': t.partNumber,
              'Množstvo': t.quantity,
              'Jednotka': t.quantityUnit,
              'Zdroj (Odkiaľ)': fromStr,
              'Cieľ (Kam)': toStr,
              'Typ': t.isLogistics ? 'LOGISTIKA' : 'VÝROBA',
              'Operácia': t.workplace,
              'Poznámka': t.note || '',
              'Status': t.auditResult ? `AUDIT ${t.auditResult}` : (t.isMissing ? 'CHÝBAL' : 'OK')
          };
      });
      const ws = XLSX.utils.json_to_sheet(exportData);
      const wb = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(wb, ws, "LOG_DATA");
      XLSX.writeFile(wb, `LOG_EXPORT_${dateFrom}_${new Date().getTime()}.xlsx`);
  };

  return (
    <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in px-2 md:px-0">
        <div className="bg-slate-900 border border-slate-700 rounded-2xl p-5 shadow-xl">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-6 border-b border-slate-800 pb-4 gap-4">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-cyan-500/10 rounded-lg text-cyan-400">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" /></svg>
                    </div>
                    <div>
                        <h2 className="text-xl font-black text-white uppercase tracking-widest leading-none">{t('tab_logs')}</h2>
                        <p className="text-[10px] text-slate-500 font-bold uppercase mt-1">Audit trail všetkých dokončených úloh</p>
                    </div>
                </div>
                <button onClick={handleExport} className="w-full md:w-auto bg-emerald-600 hover:bg-emerald-500 text-white px-6 py-3 rounded-xl font-black text-xs uppercase tracking-widest transition-all shadow-lg border-b-4 border-emerald-800 flex items-center justify-center gap-2 active:scale-95">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                    EXPORT DO EXCELU
                </button>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                <div className="space-y-1">
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Dátum Od</label>
                    <input type="date" value={dateFrom} onChange={e => setDateFrom(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-cyan-500" />
                </div>
                <div className="space-y-1">
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Dátum Do</label>
                    <input type="date" value={dateTo} onChange={e => setDateTo(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none focus:border-cyan-500" />
                </div>
                <div className="space-y-1">
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Časové Okno</label>
                    <div className="flex gap-1">
                        <input type="time" value={timeFrom} onChange={e => setTimeFrom(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-2 py-2 text-xs text-white text-center font-mono" />
                        <input type="time" value={timeTo} onChange={e => setTimeTo(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-2 py-2 text-xs text-white text-center font-mono" />
                    </div>
                </div>
                <div className="space-y-1">
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">{t('username')}</label>
                    <select value={selectedUser} onChange={e => setSelectedUser(e.target.value)} className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white focus:border-cyan-500 outline-none uppercase font-bold">
                        <option value="">VŠETCI</option>
                        {users.map(u => <option key={u.username} value={u.username}>{u.nickname || u.username}</option>)}
                    </select>
                </div>
                <div className="space-y-1">
                    <label className="block text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1">Hľadať (Part No)</label>
                    <input type="text" value={searchQuery} onChange={e => setSearchQuery(e.target.value)} placeholder="..." className="w-full bg-slate-950 border border-slate-700 rounded-lg px-3 py-2 text-xs text-white outline-none uppercase font-mono" />
                </div>
            </div>
        </div>

        <div className="bg-slate-900 border border-slate-800 rounded-2xl shadow-xl overflow-hidden min-h-[500px] flex flex-col">
            {isLoading ? (
                <div className="flex-grow flex flex-col items-center justify-center h-64 gap-4">
                    <div className="w-12 h-12 border-4 border-cyan-500 border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-cyan-500 font-black animate-pulse uppercase tracking-[0.3em] text-xs">Načítavam archívy...</p>
                </div>
            ) : (
                <div className="overflow-x-auto custom-scrollbar flex-grow">
                    <table className="w-full text-left border-collapse min-w-[1000px]">
                        <thead className="bg-slate-950 text-slate-500 text-[10px] font-black uppercase tracking-[0.1em] sticky top-0 z-10 shadow-sm">
                            <tr>
                                <th className="p-4 w-32">DÁTUM / ČAS</th>
                                <th className="p-4 w-32">OPERÁTOR</th>
                                <th className="p-4 w-40">POLOŽKA</th>
                                <th className="p-4 w-24 text-right">MNOŽSTVO</th>
                                <th className="p-4 w-48">POHYB (ODKIAĽ → KAM)</th>
                                <th className="p-4 w-32 text-center">VÝSLEDOK</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800/50 text-xs font-mono text-slate-300">
                            {filteredLogs.length > 0 ? (
                                filteredLogs.map(item => {
                                    const { fromStr, toStr } = getMovementInfo(item);
                                    const ts = item.completedAt || item.createdAt || 0;
                                    const isAuditFail = item.auditResult === 'NOK';

                                    return (
                                        <tr key={item.id} className="hover:bg-white/[0.02] transition-colors group">
                                            <td className="p-4 border-r border-slate-800/50">
                                                <div className="font-bold text-slate-200">{new Date(ts).toLocaleDateString('sk-SK')}</div>
                                                <div className="text-[10px] text-slate-500">{new Date(ts).toLocaleTimeString('sk-SK')}</div>
                                            </td>
                                            <td className="p-4 border-r border-slate-800/50">
                                                <div className="font-black text-cyan-400 uppercase">{resolveName(item.completedBy || item.createdBy)}</div>
                                                <div className="text-[8px] text-slate-600 uppercase">Zadal: {resolveName(item.createdBy)}</div>
                                            </td>
                                            <td className="p-4 border-r border-slate-800/50">
                                                <div className="bg-slate-800 px-2 py-1.5 rounded-lg text-white font-black inline-block tracking-tight">{item.partNumber}</div>
                                                {item.note && <div className="text-[9px] text-amber-500 mt-1 truncate max-w-[150px] font-bold uppercase italic">"{item.note}"</div>}
                                            </td>
                                            <td className="p-4 text-right border-r border-slate-800/50">
                                                <div className="font-black text-white text-lg">{item.quantity}</div>
                                                <div className="text-[9px] text-slate-500 uppercase">{item.quantityUnit}</div>
                                            </td>
                                            <td className="p-4 border-r border-slate-800/50">
                                                <div className="flex flex-col gap-1">
                                                    <div className="flex items-center gap-2">
                                                        <span className="text-slate-500 text-[9px] uppercase font-bold w-10">Zdroj:</span>
                                                        <span className="text-slate-300 font-bold truncate">{fromStr}</span>
                                                    </div>
                                                    <div className="flex items-center gap-2">
                                                        <span className="text-cyan-600 text-[9px] uppercase font-bold w-10">Cieľ:</span>
                                                        <span className="text-white font-black truncate">{toStr}</span>
                                                    </div>
                                                </div>
                                            </td>
                                            <td className="p-4 text-center">
                                                {isAuditFail ? (
                                                    <span className="text-red-500 font-black bg-red-500/10 px-3 py-1 rounded-full border border-red-500/20 text-[9px] tracking-tighter">AUDIT NOK</span>
                                                ) : item.auditResult === 'OK' ? (
                                                    <span className="text-emerald-500 font-black bg-emerald-500/10 px-3 py-1 rounded-full border border-emerald-500/20 text-[9px] tracking-tighter">AUDIT OK</span>
                                                ) : item.isMissing ? (
                                                    <span className="text-orange-500 font-black text-[9px] border-b border-orange-500/30">CHÝBAL</span>
                                                ) : (
                                                    <span className="text-slate-600 font-black text-[9px] opacity-40">ŠTANDARD</span>
                                                )}
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={6} className="py-32 text-center text-slate-700 uppercase font-black tracking-[0.4em] text-xs">
                                        Nenašli sa žiadne dokončené úlohy pre tento filter
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    </div>
  );
};

